class GlobalLanguageSelector extends StatelessWidget {
  const GlobalLanguageSelector({super.key});

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<String>(
      valueListenable: AppTranslations.currentLocale,
      builder: (context, locale, _) {
        return PopupMenuButton<String>(
          icon: const Icon(Icons.language),
          tooltip: 'Change Language',
          initialValue: locale,
          onSelected: (String newValue) {
            AppTranslations.currentLocale.value = newValue;
          },
          itemBuilder: (BuildContext context) {
            return AppTranslations.fullLanguageNames.entries.map((entry) {
              return PopupMenuItem<String>(
                value: entry.key,
                child: Text(entry.value),
              );
            }).toList();
          },
        );
      },
    );
  }
}
